input.command:
python3 -c "
import json
# Search for Iran province police deaths in detail
with open('articles/2026/01/08/articles.jsonl') as f:
    for line in f:
        a = json.loads(line)
        title = a.get('title','') or ''
        content = a.get('content','') or ''
        if 'iran' in title.lower() and ('police' in content.lower()[:3000] or 'security' in content.lower()[:3000]):
            # Search for specific numbers and provinces
            for phrase in ['30 police', '30 security', 'dozens of', 'police killed', 'officers killed']:
                if phrase in content.lower()[:5000]:
                    idx = content.lower().find(phrase)
                    context = content[max(0,idx-200):idx+400]
                    for prov in ['Fars', 'Khuzestan', 'Kermanshah', 'Isfahan', 'Tehran', 'Khorasan', 'Sistan', 'Kurdistan', 'Hormozgan']:
                        if prov in context:
                            print(f'Found {phrase} in {prov}: {title[:100]}')
                            break
                    else:
                        print(f'Found {phrase}: {title[:80]} | Context: {context[:200]}')
                    break
" | head -10
